//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagebatchimport("fmt""github.com/YakDriver/regexache")funcvalidName(vinterface{},kstring)(ws[]string,errors[]error){value:=v.(string)if!regexache.MustCompile(`^[0-9A-Za-z]{1}[0-9A-Za-z_-]{0,127}$`).MatchString(value){errors=append(errors,fmt.Errorf("%q(%q)mustbeupto128letters(uppercaseandlowercase),numbers,underscoresanddashes,andmuststartwithanalphanumeric.",k,v))}return}funcvalidPrefix(vinterface{},kstring)(ws[]string,errors[]error){value:=v.(string)if!regexache.MustCompile(`^[0-9A-Za-z]{1}[0-9A-Za-z_-]{0,101}$`).MatchString(value){errors=append(errors,fmt.Errorf("%q(%q)mustbeupto102letters(uppercaseandlowercase),numbers,underscoresanddashes,andmuststartwithanalphanumeric.",k,v))}return}funcvalidShareIdentifier(vinterface{},kstring)(ws[]string,errors[]error){value:=v.(string)if!regexache.MustCompile(`^[0-9A-Za-z]{0,254}[0-9A-Za-z*]?$`).MatchString(value){errors=append(errors,fmt.Errorf("%q(%q)mustbelimitedto255alphanumericcharacters,wherethelastcharactercanbeanasterisk(*).",k,v))}return}